WITH target AS (
  SELECT c.id AS candidato_id, seed.*
  FROM _seed_alrs_rs_autoria_completo seed
  JOIN candidatos c ON c.slug = seed.slug AND c.publicavel = true
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  situacao,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  target.tipo,
  target.numero,
  target.ano,
  target.ementa,
  target.fonte,
  target.proposicao_id_api,
  target.url_inteiro_teor,
  NULLIF(target.situacao, ''),
  target.coverage_id,
  target.coverage_scope,
  target.metadata
FROM target
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  situacao = EXCLUDED.situacao,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
WHERE projetos_lei.coverage_id IS NULL
   OR projetos_lei.coverage_id IN ('legislacao-unblock-19-projetos-lei-lote-b-20260508', EXCLUDED.coverage_id);

DO $$
DECLARE
  item record;
  cand_id uuid;
  total_count int;
  coverage_count int;
  metadata_ok_count int;
  old_count int;
  lme_total int;
  lme_target_count int;
BEGIN
  FOR item IN
    SELECT *
    FROM (VALUES
      ('edegar-pretto', 'edegar-pretto-alrs-completo-autoria-principal-tipos-legislativos-cutoff-20260510', 'inventario_completo_alrs_autoria_principal_tipos_legislativos_cutoff_20260510', 23, 23, 23, 23, 23),
      ('gabriel-souza', 'gabriel-souza-alrs-completo-autoria-principal-tipos-legislativos-cutoff-20260510', 'inventario_completo_alrs_autoria_principal_tipos_legislativos_cutoff_20260510', 55, 60, 60, 55, 55),
      ('juliana-brizola', 'juliana-brizola-alrs-completo-autoria-principal-tipos-legislativos-cutoff-20260510', 'inventario_completo_alrs_autoria_principal_tipos_legislativos_cutoff_20260510', 33, 35, 35, 33, 33)
    ) AS t(slug, coverage_id, coverage_scope, expected_current, expected_accepted, expected_final, expected_old_count, expected_overlap)
  LOOP
    SELECT id INTO cand_id FROM candidatos WHERE slug = item.slug AND publicavel = true;

    IF cand_id IS NULL THEN
      RAISE NOTICE '%: pos-condicao pulada porque candidato publico ausente neste banco local/CI minimo', item.slug;
      CONTINUE;
    END IF;

    SELECT count(*) INTO total_count FROM projetos_lei WHERE candidato_id = cand_id;
    SELECT count(*) INTO coverage_count
    FROM projetos_lei
    WHERE candidato_id = cand_id
      AND coverage_id = item.coverage_id
      AND coverage_scope = item.coverage_scope;
    SELECT count(*) INTO metadata_ok_count
    FROM projetos_lei
    WHERE candidato_id = cand_id
      AND metadata->>'coverage_id' = item.coverage_id
      AND metadata->>'coverage_scope' = item.coverage_scope
      AND metadata->>'coverage_status' = 'completo_escopado'
      AND metadata->>'coverage_public_status' = 'parlamentar_complete'
      AND metadata->>'tabela_alvo' = 'projetos_lei'
      AND metadata->>'legislacao_mandato_executivo_mixed' = 'false';
    SELECT count(*) INTO old_count FROM projetos_lei WHERE candidato_id = cand_id AND coverage_id = 'legislacao-unblock-19-projetos-lei-lote-b-20260508';
    SELECT count(*) INTO lme_total FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
    SELECT count(*) INTO lme_target_count
    FROM legislacao_mandato_executivo
    WHERE candidato_id = cand_id
      AND metadata->>'coverage_id' = item.coverage_id;

    IF total_count <> item.expected_final THEN
      RAISE EXCEPTION 'Pos-apply %: total projetos_lei esperado %, encontrado %', item.slug, item.expected_final, total_count;
    END IF;
    IF coverage_count <> item.expected_accepted THEN
      RAISE EXCEPTION 'Pos-apply %: coverage rows esperadas %, encontradas %', item.slug, item.expected_accepted, coverage_count;
    END IF;
    IF metadata_ok_count <> item.expected_accepted THEN
      RAISE EXCEPTION 'Pos-apply %: metadata ok esperada %, encontrada %', item.slug, item.expected_accepted, metadata_ok_count;
    END IF;
    IF old_count <> 0 THEN
      RAISE EXCEPTION 'Pos-apply %: coverage antigo deveria zerar, encontrou %', item.slug, old_count;
    END IF;
    IF lme_total <> 0 OR lme_target_count <> 0 THEN
      RAISE EXCEPTION 'Pos-apply %: LME deveria ficar 0; lme_total=% lme_target=%', item.slug, lme_total, lme_target_count;
    END IF;

    RAISE NOTICE 'ALRS completo %: projetos_lei=% coverage_rows=%', item.slug, total_count, coverage_count;
  END LOOP;
END $$;
